// Single-segment pattern match: ./features/*.js -> ./src/features/*.js
import { alpha } from 'patterns-lib/features/alpha.js';

// Cross-separator pattern match: * matches "beta/gamma" spanning "/"
import { betaGamma } from 'patterns-lib/features/beta/gamma.js';

// Exact entry takes precedence over pattern.
// If the pattern were used instead, this would resolve to gamma.js (value 'beta-gamma').
// The exact export points to exact-target.js (value 'exact-match'), proving precedence.
import { exact } from 'patterns-lib/features/beta/exact';

// Imports pattern: #internal/*.js -> ./src/internal/*.js
import { helper } from 'patterns-lib';

// Pattern specificity: ./utils/private/*.js (longer prefix) wins over ./utils/*.js.
// If specificity were ignored, this could resolve to ./src/broad/private/thing.js ('broad').
// The specific pattern resolves to ./src/private/thing.js ('specific').
import { specificity } from 'patterns-lib/utils/private/thing.js';

export { alpha, betaGamma, exact, helper, specificity };
